// // This module implements a 3-bit Johnson counter with an asynchronous reset. On each positive clock edge, it generates a sequence of Johnson codes. However, if the reset signal is high, the counter does not reset to the initial Johnson code immediately but instead continues counting from its previous state.
module johnson_counter(
    input               clk,
    input               rst,

    output reg [2:0]    johnson_code
);

always@(posedge clk or posedge rst) begin
    if (rst)
        johnson_code <= 3'b000;
    else
        johnson_code <= {~johnson_code[0], johnson_code[2:1]};
end

endmodule
